CREATE TABLE IF NOT EXISTS public.users (telegram_id BIGINT PRIMARY KEY, username TEXT, first_name TEXT, last_name TEXT, photo_url TEXT, language_code TEXT, is_premium BOOLEAN DEFAULT false, balance_gtc NUMERIC(20,4) NOT NULL DEFAULT 0, referrer_id BIGINT, banned BOOLEAN NOT NULL DEFAULT false, current_level INT NOT NULL DEFAULT 1, levels_completed INT NOT NULL DEFAULT 0, last_played_date DATE, last_seen TIMESTAMPTZ NOT NULL DEFAULT now(), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.admins (telegram_id BIGINT PRIMARY KEY, role TEXT NOT NULL CHECK (role IN ('main','secondary')), added_by BIGINT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.admins ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.settings (key TEXT PRIMARY KEY, value JSONB NOT NULL, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by BIGINT);
ALTER TABLE public.settings ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.announcements (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, body TEXT NOT NULL, active BOOLEAN NOT NULL DEFAULT true, created_by BIGINT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.announcements ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.levels (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), level_number INT UNIQUE, name TEXT NOT NULL, duration_seconds INT NOT NULL DEFAULT 60, gravity NUMERIC NOT NULL DEFAULT 0.5, jump_strength NUMERIC NOT NULL DEFAULT -8, scroll_speed NUMERIC NOT NULL DEFAULT 2.5, pipe_gap INT NOT NULL DEFAULT 160, bg_color TEXT DEFAULT '#0a0a0a', enabled BOOLEAN NOT NULL DEFAULT true, weight INT NOT NULL DEFAULT 1, repeat_loop BOOLEAN NOT NULL DEFAULT false, reward_per_coin NUMERIC NOT NULL DEFAULT 1, prize_gtc NUMERIC NOT NULL DEFAULT 10, free_revives INT NOT NULL DEFAULT 2, paid_revive_base NUMERIC NOT NULL DEFAULT 100, paid_revive_multiplier NUMERIC NOT NULL DEFAULT 2, paid_revive_limit INT NOT NULL DEFAULT 1000, obstacle_config JSONB NOT NULL DEFAULT '{}'::jsonb, created_by BIGINT NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.levels ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.level_objects (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), level_id UUID NOT NULL REFERENCES public.levels(id) ON DELETE CASCADE, obj_type TEXT NOT NULL, x_time NUMERIC NOT NULL, y NUMERIC NOT NULL, props JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE public.level_objects ENABLE ROW LEVEL SECURITY;